      primary_salesperson=EXCLUDED.primary_salesperson, account_owner=EXCLUDED.account_owner,
      logo_url=EXCLUDED.logo_url;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;
